import { Component, OnInit, OnDestroy, inject } from '@angular/core';
import { CommonModule } from '@angular/common';
import { FormsModule } from '@angular/forms';
import { Subject, lastValueFrom, takeUntil } from 'rxjs';

import { AuthService } from '../../services/timbrature-auth.adapter';
import { UsersService } from '../../services/user.service';
import { TimbratureService } from '../../services/timbrature.service';
import { DepartmentsService } from '../../services/departments.service';
import { ReportService } from '../../services/report.service';
import { CompanyService } from '../../services/company.service';

import { User, Department, Timbratura } from '../../models';
import { LucideAngularModule } from 'lucide-angular';

interface KpiData {
  oreTotali: number;
  presenzeMedie: number;
  oreMediePerDipendente: number;
  tassoPuntualita: number;
}

interface PerformanceDipendente {
  nome: string;
  oreTotali: number;
  oreMedieGiorno: number;
  giorniPresente: number;
  giorniTotali: number;
  puntualita: number;
  attivo: boolean;
}

interface OrePerDipendente {
  nome: string;
  ore: number;
}

@Component({
  selector: 'app-kpi',
  standalone: true,
  imports: [CommonModule, FormsModule, LucideAngularModule],
  templateUrl: './kpi.component.html',
  styleUrls: ['./kpi.component.css']
})
export class KpiComponent implements OnInit, OnDestroy {
  private authService = inject(AuthService);
  private usersService = inject(UsersService);
  private timbratureService = inject(TimbratureService);
  private departmentsService = inject(DepartmentsService);
  private reportService = inject(ReportService);
  private companyService = inject(CompanyService);

  currentUser: User | null = null;

  // Filtri
  filtroPeriodo = 'mese';
  filtroDipendente = 'tutti';
  filtroReparto = 'tutti';

  // Dati per filtri
  dipendenti: User[] = [];
  reparti: Department[] = [];

  // Dati KPI
  kpi: KpiData = {
    oreTotali: 0,
    presenzeMedie: 0,
    oreMediePerDipendente: 0,
    tassoPuntualita: 0
  };
  orePerDipendente: OrePerDipendente[] = [];
  performanceDipendenti: PerformanceDipendente[] = [];
  distribuzioneOrari: { fascia: string; percentuale: number }[] = [];
  andamentoSettimanale: { giorno: string; ore: number }[] = [];
  anomalie: { tipo: string; descrizione: string; dipendente: string; data: Date }[] = [];

  isLoading = true;
  private destroy$ = new Subject<void>();

  ngOnInit() {
    this.authService.currentUser$
      .pipe(takeUntil(this.destroy$))
      .subscribe(async (user) => {
        this.currentUser = user;
        if (!user) return;
        await this.loadInitialData();
      });
  }

  ngOnDestroy() {
    this.destroy$.next();
    this.destroy$.complete();
  }

  private async loadInitialData() {
    this.isLoading = true;
    try {
      await Promise.all([
        this.loadReparti(),
        this.loadDipendenti()
      ]);
      await this.loadKPI();
    } catch (error) {
      console.error('Errore caricamento dati iniziali', error);
    } finally {
      this.isLoading = false;
    }
  }

  private async loadReparti() {
    if (!this.currentUser?.company_id) {
      this.reparti = [];
      return;
    }
    try {
      this.reparti = await lastValueFrom(
        this.departmentsService.getByCompany(this.currentUser.company_id)
      );
    } catch (error) {
      console.error('Errore caricamento reparti', error);
      this.reparti = [];
    }
  }

  private async loadDipendenti() {
    if (!this.currentUser?.company_id) {
      this.dipendenti = [];
      return;
    }
    try {
      let employees = await lastValueFrom(
        this.usersService.getByCompany(this.currentUser.company_id)
      );

      // Filtra in base al ruolo
      if (this.authService.hasRole('employee')) {
        employees = employees.filter(e => e.id === this.currentUser?.id);
      } else if (this.authService.hasRole('manager')) {
        const company = await lastValueFrom(
          this.companyService.getForUser(this.currentUser.id, this.currentUser.company_id)
        );
        employees = this.companyService.filterEmployeesByVisibility(
          employees,
          company,
          this.currentUser.id
        );
      }

      this.dipendenti = employees;
    } catch (error) {
      console.error('Errore caricamento dipendenti', error);
      this.dipendenti = [];
    }
  }

  private getDateRange(period: string): { start: Date; end: Date } {
    const now = new Date();
    const start = new Date(now);
    let end = new Date(now);

    switch (period) {
      case 'oggi':
        start.setHours(0, 0, 0, 0);
        end = new Date(start);
        end.setDate(end.getDate() + 1);
        break;
      case 'settimana':
        // Lunedì della settimana corrente
        const day = (now.getDay() + 6) % 7;
        start.setDate(now.getDate() - day);
        start.setHours(0, 0, 0, 0);
        end = new Date(start);
        end.setDate(start.getDate() + 7);
        break;
      case 'trimestre':
        start.setMonth(now.getMonth() - 3);
        start.setHours(0, 0, 0, 0);
        end = new Date(now);
        end.setHours(23, 59, 59, 999);
        break;
      case 'mese':
      default:
        start.setDate(1);
        start.setHours(0, 0, 0, 0);
        end = new Date(start.getFullYear(), start.getMonth() + 1, 1);
        break;
    }
    return { start, end };
  }

  async loadKPI() {
    if (!this.currentUser?.company_id) return;

    this.isLoading = true;
    try {
      const companyId = this.currentUser.company_id;
      const range = this.getDateRange(this.filtroPeriodo);

      // Costruisci filtri per timbrature
      const filters: any = {
        company_id: companyId,
        start_ts: {
          gte: range.start.toISOString(),
          lt: range.end.toISOString()
        }
      };

      if (this.filtroDipendente && this.filtroDipendente !== 'tutti') {
        filters.user_id = this.filtroDipendente;
      }

      let timbrature = await lastValueFrom(
        this.timbratureService.getFiltered(filters)
      );

      // Se non è admin, filtra per id dipendenti visibili
      if (!this.authService.hasRole('admin')) {
        const allowedIds = new Set(this.dipendenti.map(d => d.id));
        timbrature = timbrature.filter(t => allowedIds.has(t.user_id));
      }

      // Filtro reparto lato client
      if (this.filtroReparto && this.filtroReparto !== 'tutti') {
        const userDeptMap = new Map(this.dipendenti.map(d => [d.id, d.department_id]));
        timbrature = timbrature.filter(t => userDeptMap.get(t.user_id) === this.filtroReparto);
      }

      this.calcolaKPI(timbrature, range);
    } catch (error) {
      console.error('Errore caricamento KPI', error);
    } finally {
      this.isLoading = false;
    }
  }

  private calcolaKPI(timbrature: Timbratura[], range: { start: Date; end: Date }) {
    // Ore totali
    const totalMinutes = timbrature.reduce((acc, t) => acc + (t.total_minutes || 0), 0);
    this.kpi.oreTotali = Math.round((totalMinutes / 60) * 10) / 10;

    // Giorni nel range
    const days: Date[] = [];
    for (let d = new Date(range.start); d < range.end; d.setDate(d.getDate() + 1)) {
      days.push(new Date(d));
    }

    // Presenze medie
    const presenzePerGiorno = days.map(day => {
      const dayStart = new Date(day); dayStart.setHours(0, 0, 0, 0);
      const dayEnd = new Date(dayStart); dayEnd.setDate(dayEnd.getDate() + 1);
      const usersSet = new Set(
        timbrature
          .filter(t => {
            const ts = new Date(t.start_ts);
            return ts >= dayStart && ts < dayEnd;
          })
          .map(t => t.user_id)
      );
      return usersSet.size;
    });
    const totaleGiorni = presenzePerGiorno.length || 1;
    this.kpi.presenzeMedie = Math.round(
      (presenzePerGiorno.reduce((a, b) => a + b, 0) / totaleGiorni) * 10
    ) / 10;

    // Mappe per utente
    const minutesByUser: Record<string, number> = {};
    const daysByUser: Record<string, Set<string>> = {};
    let punctualCount = 0;

    timbrature.forEach(t => {
      const uid = t.user_id;
      minutesByUser[uid] = (minutesByUser[uid] || 0) + (t.total_minutes || 0);
      const dayKey = new Date(t.start_ts).toISOString().slice(0, 10);
      if (!daysByUser[uid]) daysByUser[uid] = new Set();
      daysByUser[uid].add(dayKey);

      // Puntualità: inizio <= 9:00
      try {
        const startHour = new Date(t.start_ts).getHours();
        if (startHour <= 9) punctualCount++;
      } catch { /* ignore */ }
    });

    const userMap = new Map(this.dipendenti.map(d => [d.id, d]));

    // Ore per dipendente
    this.orePerDipendente = Object.entries(minutesByUser)
      .map(([uid, minutes]) => {
        const user = userMap.get(uid);
        const nome = user ? `${user.first_name} ${user.last_name}` : uid;
        return { nome, ore: Math.round((minutes / 60) * 10) / 10 };
      })
      .sort((a, b) => b.ore - a.ore);

    // Performance dipendenti
    this.performanceDipendenti = Object.entries(minutesByUser).map(([uid, minutes]) => {
      const user = userMap.get(uid);
      const nome = user ? `${user.first_name} ${user.last_name}` : uid;
      const giorni = daysByUser[uid]?.size || 0;
      const ore = Math.round((minutes / 60) * 10) / 10;
      return {
        nome,
        oreTotali: ore,
        oreMedieGiorno: giorni > 0 ? Math.round((ore / giorni) * 10) / 10 : 0,
        giorniPresente: giorni,
        giorniTotali: days.length,
        puntualita: 0,
        attivo: user?.is_active ?? true
      };
    });

    // Ore medie per dipendente
    const numDip = this.filtroDipendente !== 'tutti' ? 1 : (this.dipendenti.length || 1);
    this.kpi.oreMediePerDipendente = Math.round((this.kpi.oreTotali / numDip) * 10) / 10;

    // Tasso puntualità
    this.kpi.tassoPuntualita = timbrature.length > 0
      ? Math.round((punctualCount / timbrature.length) * 100) / 100
      : 0;

    // Distribuzione orari di inizio
    const buckets = { before8: 0, b8_830: 0, b830_9: 0, after9: 0 };
    timbrature.forEach(t => {
      try {
        const d = new Date(t.start_ts);
        const minutesOfDay = d.getHours() * 60 + d.getMinutes();
        if (minutesOfDay < 8 * 60) buckets.before8++;
        else if (minutesOfDay < 8 * 60 + 30) buckets.b8_830++;
        else if (minutesOfDay < 9 * 60) buckets.b830_9++;
        else buckets.after9++;
      } catch { /* ignore */ }
    });
    const totalStarts = timbrature.length || 1;
    this.distribuzioneOrari = [
      { fascia: 'Prima delle 8:00', percentuale: Math.round((buckets.before8 / totalStarts) * 100) / 100 },
      { fascia: '8:00 - 8:30', percentuale: Math.round((buckets.b8_830 / totalStarts) * 100) / 100 },
      { fascia: '8:30 - 9:00', percentuale: Math.round((buckets.b830_9 / totalStarts) * 100) / 100 },
      { fascia: 'Dopo le 9:00', percentuale: Math.round((buckets.after9 / totalStarts) * 100) / 100 }
    ];

    // Andamento settimanale (ultimi 7 giorni)
    const last7: { giorno: string; ore: number }[] = [];
    for (let i = 6; i >= 0; i--) {
      const d = new Date();
      d.setHours(0, 0, 0, 0);
      d.setDate(d.getDate() - i);
      const dayStart = new Date(d);
      const dayEnd = new Date(dayStart);
      dayEnd.setDate(dayEnd.getDate() + 1);
      const minutesDay = timbrature
        .filter(t => {
          const ts = new Date(t.start_ts);
          return ts >= dayStart && ts < dayEnd;
        })
        .reduce((acc, t) => acc + (t.total_minutes || 0), 0);
      const giornoLabel = ['Lun', 'Mar', 'Mer', 'Gio', 'Ven', 'Sab', 'Dom'][d.getDay() === 0 ? 6 : d.getDay() - 1];
      last7.push({ giorno: giornoLabel, ore: Math.round((minutesDay / 60) * 10) / 10 });
    }
    this.andamentoSettimanale = last7;

    // Anomalie
    this.anomalie = timbrature
      .filter(t => !t.end_ts || (t.total_minutes || 0) <= 0)
      .map(t => {
        const user = userMap.get(t.user_id);
        const nome = user ? `${user.first_name} ${user.last_name}` : t.user_id;
        return {
          tipo: !t.end_ts ? 'Uscita mancante' : 'Durata sospetta',
          descrizione: !t.end_ts ? 'Uscita non registrata' : 'Durata <= 0',
          dipendente: nome,
          data: new Date(t.start_ts)
        };
      });
  }

  onFiltroChange() {
    this.loadKPI();
  }

  async aggiornaDati() {
    await this.loadKPI();
  }

  async esportaReport() {
    if (!this.currentUser?.company_id) return;
    try {
      const blob = await lastValueFrom(
        this.reportService.exportReport('xlsx', {
          company_id: this.currentUser.company_id,
          tipo: 'kpi',
          periodo: this.filtroPeriodo,
          dipendente: this.filtroDipendente,
          reparto: this.filtroReparto
        })
      );
      const url = window.URL.createObjectURL(blob);
      const a = document.createElement('a');
      a.href = url;
      a.download = `kpi_${new Date().toISOString().slice(0,10)}.xlsx`;
      a.click();
      window.URL.revokeObjectURL(url);
    } catch (error) {
      console.error('Errore esportazione report KPI', error);
      alert('Errore durante l\'esportazione');
    }
  }

  getAltezzaBarra(ore: number): number {
    const maxOre = Math.max(...this.orePerDipendente.map(item => item.ore), 0.1);
    return (ore / maxOre) * 100;
  }

  get isAdmin(): boolean { return this.authService.hasRole('admin'); }
  get isManager(): boolean { return this.authService.hasRole('manager'); }
  get isEmployee(): boolean { return this.authService.hasRole('employee'); }

}
